// ==========================================
// 0. FUNCIONES AUXILIARES (HASHING)
// ==========================================
function generarCodigoHash(texto) {
    let hash = 0;
    let str = (texto || "SIN_NOMBRE").toUpperCase().trim();
    for (let i = 0; i < str.length; i++) {
        let char = str.charCodeAt(i);
        hash = ((hash << 5) - hash) + char;
        hash = hash & hash;
    }
    return "GEN-" + Math.abs(hash).toString(16).toUpperCase().padStart(7, '0');
}

// ==========================================
// 1. CONFIGURACIÓN DEL NODO INICIAL (MOCHILA)
// ==========================================
const mochila = $('Trigger Documento a procesar').first().json || {};
const fileId = mochila.file_id || "";
const rutProveedor = mochila.rut_proveedor || "";
const numeroDocumento = mochila.numero_documento || "";
const tipoDocumento = mochila.tipo_documento || "Factura";
const fechaEmision = mochila.fecha_emision || "";

// MAGIA: Ahora el nombre limpio viene directamente desde el WF 01 en la mochila
const nombreProveedor = mochila.nombre_empresa || mochila.nombre_proveedor || "Desconocido";

// ==========================================
// 2. RECUPERAR EL JSON DE GEMINI
// ==========================================
const dataExtraida = $('Code (Parsear JSON)').first().json || {};

if (dataExtraida.error_extraccion) {
    return [{ json: { error: "Fallo en extracción previa", detalle: dataExtraida.mensaje_error } }];
}

// ==========================================
// 3. TU MOTOR MATEMÁTICO
// ==========================================
const lineasOriginales = dataExtraida.lineas_detalle || [];
const fletesGlobalesArray = dataExtraida.fletes_globales || [];
const descGlobalPorcentaje = Number(dataExtraida.descuento_global_porcentaje) || 0;

let pozoFleteGlobal = fletesGlobalesArray.reduce((sum, f) => sum + (Number(f.monto_total) || 0), 0);
let lineasProductos = [];

for (let linea of lineasOriginales) {
    let esFlete = linea.es_flete_linea === true || String(linea.es_flete_linea).toLowerCase() === "true";
    let descripcionLimpia = (linea.descripcion || "").toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");
    let pareceFlete = descripcionLimpia.includes("flete") || descripcionLimpia.includes("despacho") || descripcionLimpia.includes("logistica") || descripcionLimpia.includes("logistics") || descripcionLimpia.includes("almacenamiento") || descripcionLimpia.includes("distribucion");

    if (esFlete || pareceFlete) {
        let cantFlete = Number(linea.cantidad_total_impresa) || 1;
        let precioFlete = Number(linea.precio_base_unitario) || Number(linea.monto_total_impreso) || Number(linea.monto_total_neto) || 0;
        pozoFleteGlobal += (cantFlete * precioFlete);
    } else {
        lineasProductos.push(linea);
    }
}

let lineasProcesadas = lineasProductos.map(linea => {
    let cant = Number(linea.cantidad_total_impresa) || (Number(linea.cantidad_cajas || 0) + Number(linea.cantidad_unidades || 0)) || 1;
    let precioUnit = Number(linea.precio_base_unitario) || 0;

    let multiplicador = tipoDocumento.toLowerCase().includes("credito") ? -1 : 1;
    let totalBrutoLinea = (cant * precioUnit) * multiplicador;

    let descMontoLocal = 0;
    let desc = linea.descuentos || {};
    if (desc.monto_total !== null && desc.monto_total !== undefined) {
        descMontoLocal = Number(desc.monto_total) * multiplicador;
    } else if (desc.porcentaje !== null && desc.porcentaje !== undefined) {
        descMontoLocal = totalBrutoLinea * (Number(desc.porcentaje) / 100);
    } else if (desc.monto_unitario !== null && desc.monto_unitario !== undefined) {
        descMontoLocal = (cant * Number(desc.monto_unitario)) * multiplicador;
    }

    let subtotalNetoLinea = totalBrutoLinea - descMontoLocal;
    let descMontoGlobal = subtotalNetoLinea * (descGlobalPorcentaje / 100);

    let montoDescuentoTotal = descMontoLocal + descMontoGlobal;
    let montoTotalNeto = subtotalNetoLinea - descMontoGlobal;

    let montoIla = 0;
    let imp = linea.impuestos || {};
    let porcIlaAplicado = 0;

    if (imp.monto_total_impreso !== null && imp.monto_total_impreso !== undefined) {
        montoIla = Number(imp.monto_total_impreso) * multiplicador;
        porcIlaAplicado = montoTotalNeto !== 0 ? Math.abs((montoIla / montoTotalNeto) * 100) : 0;

        if (porcIlaAplicado > 35) {
            montoIla = 0;
            porcIlaAplicado = 0;
        }
    } else if (imp.porcentaje_ila_inferido !== null && imp.porcentaje_ila_inferido !== undefined) {
        porcIlaAplicado = Number(imp.porcentaje_ila_inferido);
        montoIla = montoTotalNeto * (porcIlaAplicado / 100);
    }

    let fleteImpreso = null;
    if (linea.monto_flete_total_impreso !== null && linea.monto_flete_total_impreso !== undefined) {
        fleteImpreso = Number(linea.monto_flete_total_impreso) * multiplicador;
    }

    return {
        ...linea,
        cantidad_calculada: cant * multiplicador,
        precio_unitario_calculado: precioUnit,
        monto_descuento_calculado: montoDescuentoTotal,
        monto_total_neto_calculado: montoTotalNeto,
        monto_ila_calculado: montoIla,
        porcentaje_ila_aplicado: porcIlaAplicado,
        monto_flete_impreso_calculado: fleteImpreso
    };
});

const totalNetoFactura = lineasProcesadas.reduce((sum, linea) => sum + linea.monto_total_neto_calculado, 0);

// ==========================================
// 4. GENERACIÓN DE MATRIZ CUADRADA PARA EXCEL
// ==========================================
let resultadosAplanados = [];

for (let linea of lineasProcesadas) {
    let fleteAsignado = 0;
    if (linea.monto_flete_impreso_calculado !== null) {
        fleteAsignado = linea.monto_flete_impreso_calculado; 
    } else {
        let proporcion = totalNetoFactura !== 0 ? (linea.monto_total_neto_calculado / totalNetoFactura) : 0;
        fleteAsignado = pozoFleteGlobal * proporcion; 
    }

    let montoIlaRedondeado = Math.round(linea.monto_ila_calculado);
    let costoTotalLinea = linea.monto_total_neto_calculado + fleteAsignado + montoIlaRedondeado;
    let baseIva = linea.monto_total_neto_calculado + fleteAsignado;
    let iva19Linea = baseIva * 0.19;
    let montoIvaRedondeado = Math.round(iva19Linea);
    let valorTotalLinea = costoTotalLinea + montoIvaRedondeado;
    let costoUnidadCompra = linea.cantidad_calculada !== 0 ? (costoTotalLinea / linea.cantidad_calculada) : 0;

    let codProducto = linea.codigo_producto;
    if (!codProducto || codProducto.toString().trim() === "" || codProducto === "null") {
        codProducto = generarCodigoHash(linea.descripcion);
    }

    resultadosAplanados.push({
        json: {
            "file_id": fileId,
            "rut_proveedor": rutProveedor,
            "nombre_proveedor": nombreProveedor,
            "numero_documento": numeroDocumento,
            "tipo_documento": tipoDocumento,
            "fecha_emision": fechaEmision,

            "codigo_producto": codProducto,
            "descripcion": linea.descripcion || "SIN_DESCRIPCION",
            "unidad_compra": linea.unidad_compra || "UN",
            "cantidad": parseFloat(linea.cantidad_calculada.toFixed(2)),
            "porcentaje_ila": parseFloat(Number(linea.porcentaje_ila_aplicado).toFixed(2)),

            "precio_base_unitario": parseFloat(linea.precio_unitario_calculado.toFixed(2)),
            "monto_descuento": parseFloat(linea.monto_descuento_calculado.toFixed(2)),
            "monto_total_neto": parseFloat(linea.monto_total_neto_calculado.toFixed(2)),
            "flete_ponderado": parseFloat(fleteAsignado.toFixed(2)),
            "costo_unidad_compra": parseFloat(costoUnidadCompra.toFixed(2)),

            "monto_ila": montoIlaRedondeado,
            "iva_19": montoIvaRedondeado,
            "costo_total_linea": Math.round(costoTotalLinea),
            "valor_total_linea": Math.round(valorTotalLinea),
            "correo_origen": mochila.correo_origen || "" 
        }
    });
}

return resultadosAplanados.length > 0 ? resultadosAplanados : [{ json: { error: "No se encontraron productos" } }];

for (let item of $input.all()) {
  // 1. Datos para renombrar el Excel
  const mochila = $('Trigger Documento a procesar').first().json;
  const nombreProv = $('Code (Motor Matemático y Aplanado)').first().json.nombre_proveedor;

  const nombrePerfecto = `${mochila.fecha_emision}_${nombreProv}_${mochila.numero_documento}_${mochila.tipo_documento}.xlsx`;

  // Asegurarnos de que el bolsillo de binarios exista
  if (!item.binary) item.binary = {};

  // 2. Renombrar el Excel (si existe)
  if (item.binary.excel_procesado) {
    item.binary.excel_procesado.fileName = nombrePerfecto;
  }

  // 3. EL RESCATE DE LA IMAGEN ORIGINAL
  // Vamos a buscar el binario 'data' directo del nodo que descargó el archivo al inicio
  const imagenOriginal = $('Descargar Documento').first().binary?.data;

  if (imagenOriginal) {
    // Lo guardamos en el bolsillo 'data' actual para que Gmail lo encuentre
    item.binary.data = imagenOriginal;
  }
}

return $input.all();

let resultados = [];

for (let item of $input.all()) {
    try {
        let rawText = item.json?.content?.parts?.[0]?.text;
        if (!rawText) throw new Error("No se encontró texto de Gemini.");

        let cleanText = rawText.replace(/```json/gi, '').replace(/```/gi, '').trim();
        let inicio = cleanText.indexOf('{');
        let fin = cleanText.lastIndexOf('}');

        if(inicio !== -1 && fin !== -1) {
            cleanText = cleanText.substring(inicio, fin + 1);
        }
        resultados.push({ json: JSON.parse(cleanText) });
    } catch (error) {
        resultados.push({ json: { error_extraccion: true, mensaje_error: error.message } });
    }
}
return resultados;
